/**
 * HTML Prototype Renderer for Design Workshop Assistant
 *
 * Pure function: receives DesignSpecV1, returns a self-contained clickable prototype HTML string.
 * Single-file, no external runtime dependencies.
 * Fonts: Open Sans embedded as base64 @font-face when src/assets/fonts/ files are present
 * (generated by scripts/generate-font-face-css.ts at build time). Falls back to system
 * sans-serif with no external calls when font files are absent.
 * Jazz DS tokens applied via CSS custom properties.
 */

import type { DesignSpecV1, BlockSpec } from './types'
import { FONT_FACE_CSS } from '../../generated/fontFaceCSS'
import { isLikelyTicker, getTickerLogoDataUri, getTickerName } from './stockLogos'
import { getBrandLogoDataUri } from './brandLogos/index'

/** Returns the best available logo URI: real brand SVG > letter-avatar fallback */
function getLogoUri(ticker: string): string {
  return getBrandLogoDataUri(ticker) ?? getTickerLogoDataUri(ticker)
}

