function renderTabBar(appType?: string): string {
  const key = (appType ?? 'default').toLowerCase()
  const tabs = ARCHETYPE_TABS[key] ?? ARCHETYPE_TABS['default']
  const items = tabs.map((label, i) => {
    const isActive = i === 0
    const iconPaths = LUCIDE_HTML_SVGS[label] ?? LUCIDE_HTML_SVGS['Activity']
    const color = isActive ? 'var(--jazz-primary)' : 'var(--jazz-muted)'
    return `<button class="tab-item${isActive ? ' active' : ''}">
  <svg viewBox="0 0 24 24" fill="none" stroke="${color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">${iconPaths}</svg>
  <span class="tab-item-label">${escapeHtml(label)}</span>
</button>`
  }).join('\n')
  return `<div class="tab-bar">\n${items}\n</div>`
}

function resolvePadding(padding: number | { top?: number; right?: number; bottom?: number; left?: number } | undefined): string {
  const MIN = 16
  if (padding === undefined) return `${MIN}px`
  if (typeof padding === 'number') {
    const p = Math.max(padding, MIN)
    return `${p}px`
  }
  const t = Math.max(padding.top ?? MIN, MIN)
  const r = Math.max(padding.right ?? MIN, MIN)
  const b = Math.max(padding.bottom ?? MIN, MIN)
  const l = Math.max(padding.left ?? MIN, MIN)
  return `${t}px ${r}px ${b}px ${l}px`
}

export function renderToHtml(spec: DesignSpecV1, useWireframe = false): string {
  const title = spec.meta?.title ?? 'FiFi Prototype'
  const screens = spec.screens ?? []
  const total = screens.length

  // Handoff card metadata
  const userRequest = spec.meta?.userRequest ?? ''
  const promptDisplay = userRequest.length > 120
    ? userRequest.slice(0, 117) + '…'
    : userRequest
  const now = new Date()
  const dateStr = now.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })

  const appType = spec.meta?.intent?.appType ?? 'default'
  const tabBarHtml = renderTabBar(appType)

  const screenHtml = screens.map((screen, i) => {
    const gap = Math.max(screen.layout?.gap ?? 16, 12)
    const paddingCss = resolvePadding(screen.layout?.padding)
    const allBlocks = screen.blocks ?? []
    const bodyBlocks = allBlocks.filter(b => b.type !== 'button')
    const actionBlocks = allBlocks.filter(b => b.type === 'button')

    const bodyHtml = bodyBlocks.map(b => renderBlock(b, gap)).join('\n    ')
    const actionsHtml = actionBlocks.length > 0
      ? `\n<div class="screen-actions">\n  ${actionBlocks.map(b => renderBlock(b, 0)).join('\n  ')}\n</div>`
      : ''
    const activeClass = i === 0 ? ' active' : ''

    return `<div class="screen-wrapper${activeClass}" data-screen="${i}">
  <div class="screen-title-bar">${escapeHtml(screen.name)}</div>
  <div class="screen-content" style="padding:${paddingCss}">
    ${bodyHtml}
  </div>${actionsHtml}
</div>`
  }).join('\n')

  const dotsHtml = screens.map((_, i) =>
    `<button class="nav-dot${i === 0 ? ' active' : ''}" onclick="goToScreen(${i})" aria-label="Screen ${i + 1}"></button>`
  ).join('\n      ')

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>${escapeHtml(title)}</title>
  ${!useWireframe && FONT_FACE_CSS ? `<style>${FONT_FACE_CSS}</style>` : ''}
  <style>
    :root { ${useWireframe ? WIREFRAME_CSS_VARS.trim() : JAZZ_CSS_VARS.trim()} }
    ${BASE_CSS.trim()}
    ${PANEL_CSS.trim()}
    ${useWireframe ? WIREFRAME_OVERRIDE_CSS.trim() : ''}
  </style>
</head>
<body${useWireframe ? ' class="wireframe"' : ''}>

  <div class="handoff-card" role="banner" aria-label="Design handoff summary">
    <div class="handoff-card-top">
      <span class="handoff-card-title">${escapeHtml(title)}</span>
      <div class="handoff-card-badges">
        <span class="handoff-badge handoff-badge--source">FigmAI Design Workshop</span>
        <span class="handoff-badge handoff-badge--ds">${useWireframe ? 'Wireframe' : 'Jazz DS'}</span>
        <span class="handoff-badge handoff-badge--screens">${total} screen${total !== 1 ? 's' : ''}</span>
        <span class="handoff-badge handoff-badge--date">${escapeHtml(dateStr)}</span>
      </div>
    </div>
    ${promptDisplay ? `<div class="handoff-card-prompt">"${escapeHtml(promptDisplay)}"</div>` : ''}
  </div>

  <div class="proto-workspace">
    <div class="proto-left">
      <div class="phone-frame">
        <div class="status-bar">
          <span class="status-bar-time">9:41</span>
          <div class="status-bar-icons">
            <span>●●●</span>
            <span>WiFi</span>
            <span>🔋</span>
          </div>
        </div>
        ${screenHtml}
        ${tabBarHtml}
      </div>

      <nav class="proto-nav" aria-label="Screen navigation">
        <div class="nav-dots">
          ${dotsHtml}
        </div>
        <div class="nav-arrows">
          <button class="nav-arrow-btn" id="nav-back" onclick="goToScreen(currentScreen - 1)">← Back</button>
          <span class="nav-screen-counter" id="nav-counter">1 / ${total}</span>
          <button class="nav-arrow-btn" id="nav-next" onclick="goToScreen(currentScreen + 1)">Next →</button>
        </div>
      </nav>
    </div>

    ${PANEL_HTML}
  </div>

  <div class="cs-toast" id="cs-toast"></div>

  <script>${PROTOTYPE_JS}${PANEL_JS}</script>
</body>
</html>`
}
